  - `docsPath`, `docsLabel`: Documentation links
  - `blurb`: Short description
  - `aliases`: Alternative names
  - `systemImage`: UI icon identifier
  - `markdownCapable`: If true, channel supports Markdown
- `bundle.stageRuntimeDependencies`: Whether to bundle dependencies

### 4. **Entry Point Files**

**`index.ts` Pattern (main entry point):**
```typescript
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
import { ircPlugin } from "./src/channel.js";
import { setIrcRuntime } from "./src/runtime.js";

export { ircPlugin } from "./src/channel.js";
export { setIrcRuntime } from "./src/runtime.js";

export default defineChannelPluginEntry({
  id: "irc",
  name: "IRC",
  description: "IRC channel plugin",
  plugin: ircPlugin as ChannelPlugin,
  setRuntime: setIrcRuntime,
});
```

**`setup-entry.ts` Pattern (setup-only mode):**
```typescript
import { defineSetupPluginEntry } from "openclaw/plugin-sdk/core";
import { ircPlugin } from "./src/channel.js";

export default defineSetupPluginEntry(ircPlugin);
```

**Export barrels (`api.ts`, `runtime-api.ts`, others):**
- `api.ts`: Public API for tests and cross-package use
- `runtime-api.ts`: Re-exports from plugin SDK for local use (thin barrel)
- `channel-config-api.ts`, `test-api.ts`, etc.: Specialized barrels

### 5. **ChannelPlugin Interface** (Core Type)

Location: `src/channels/plugins/types.plugin.ts`

The `ChannelPlugin<ResolvedAccount, Probe, Audit>` type has these key properties:

```typescript
export type ChannelPlugin<ResolvedAccount = any, Probe = unknown, Audit = unknown> = {
  id: ChannelId;
  meta: ChannelMeta;
  capabilities: ChannelCapabilities;

  // Setup & Config
  setupWizard?: ChannelPluginSetupWizard;
  config: ChannelConfigAdapter<ResolvedAccount>;
  configSchema?: ChannelConfigSchema;
  setup?: ChannelSetupAdapter;

  // Routing & Messaging
  messaging?: ChannelMessagingAdapter;
  resolver?: ChannelResolverAdapter;
  directory?: ChannelDirectoryAdapter;

  // Security & Pairing
  pairing?: ChannelPairingAdapter;
  security?: ChannelSecurityAdapter<ResolvedAccount>;

  // Delivery
  outbound?: ChannelOutboundAdapter;

  // Lifecycle & Status
  status?: ChannelStatusAdapter<ResolvedAccount, Probe, Audit>;
  gateway?: ChannelGatewayAdapter<ResolvedAccount>;
  lifecycle?: ChannelLifecycleAdapter;

  // Groups & Threading
  groups?: ChannelGroupAdapter;
  threading?: ChannelThreadingAdapter;

  // Advanced Adapters
  mentions?: ChannelMentionAdapter;
  auth?: ChannelAuthAdapter;
  approvals?: ChannelApprovalAdapter;
  approvalCapability?: ChannelApprovalCapability;
  elevated?: ChannelElevatedAdapter;
  commands?: ChannelCommandAdapter;
  actions?: ChannelMessageActionAdapter;
  allowlist?: ChannelAllowlistAdapter;
  heartbeat?: ChannelHeartbeatAdapter;
  agentPrompt?: ChannelAgentPromptAdapter;
  agentTools?: ChannelAgentToolFactory | ChannelAgentTool[];

  // Reload & Streaming
  reload?: { configPrefixes: string[]; noopPrefixes?: string[] };
  streaming?: ChannelStreamingAdapter;
};
```

### 6. **Source Code Organization**

**Typical structure for `/extensions/{channel-name}/src/`:**

```
src/
├── channel.ts              # Main ChannelPlugin export
├── runtime.ts              # Runtime store (getRuntime, setRuntime)
├── runtime-api.ts          # Re-export barrel from plugin SDK
├── accounts.ts             # Account resolution helpers
├── types.ts                # TypeScript types (Config, Account, etc.)
├── config-schema.ts        # Zod schema validation
├── config-ui-hints.ts      # UI display hints
├── setup-core.ts           # ChannelSetupAdapter implementation
├── setup-surface.ts        # ChannelSetupWizard implementation
├── send.ts                 # Outbound message sending
├── inbound.ts              # Inbound message processing (if applicable)
├── probe.ts                # Health/connection checking
├── monitor.ts              # Long-running provider monitor
├── normalize.ts            # Target/ID normalization
├── policy.ts               # Group & DM policy resolution
├── *.test.ts               # Colocated tests
└── subdirs/                # For complex channels (e.g., telegram/bot/*)
```

**Key Patterns:**

1. **Accounts Resolution** (`accounts.ts`):
   - Uses `createAccountListHelpers()` from plugin SDK
   - Resolves merged account configs with environment variables/files
   - Returns typed `ResolvedAccount` object
   - Handles password resolution (env, file, config, none)

2. **Config Schema** (`config-schema.ts`):
   - Uses Zod schemas from plugin SDK
   - `buildChannelConfigSchema()` helper creates final schema
   - Includes UI hints for config fields
   - Example: `IrcAccountSchema` validates IRC-specific fields

3. **Channel Plugin Creation**:
   - IRC/Telegram use `createChatChannelPlugin()` helper from plugin SDK
   - Provides shortcuts for common chat channel patterns:
     - `security`: DM policy, allowlist, warnings
     - `pairing`: Text-based pairing notifications
     - `threading`: Reply mode resolution
     - `outbound`: Text/media/poll sending with chunking

