/** Boards are prefixed with "#"; direct targets are plain usernames. */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Normalize a raw PulseBoard messaging target.
 *
 * Accepted forms:
 *   #general          → #general  (board)
 *   board:general     → #general  (board, prefix stripped)
 *   pulseboard:#ops   → #ops      (protocol prefix stripped)
 *   @alice            → alice     (direct, @ stripped)
 *   user:alice        → alice     (direct, prefix stripped)
 *   alice             → alice     (direct, plain username)
 *
 * Returns undefined for empty or structurally invalid inputs.
 */
export function normalizePulseboardMessagingTarget(raw: string): string | undefined {
  let target = raw.trim();
  if (!target) {
    return undefined;
  }

  // Strip "pulseboard:" protocol prefix.
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // Strip "board:" prefix and ensure "#" prefix.
  if (target.toLowerCase().startsWith("board:")) {
    const boardName = target.slice("board:".length).trim();
    if (!boardName) {
      return undefined;
    }
    target = boardName.startsWith("#") ? boardName : `#${boardName}`;
  }

  // Strip "user:" or "@" prefix for direct targets.
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  } else if (target.startsWith("@")) {
    target = target.slice(1).trim();
  }

  if (!target || !looksLikePulseboardTargetId(target)) {
    return undefined;
  }
  return target;
}

/** Lightweight heuristic: valid targets have no whitespace or control characters. */
export function looksLikePulseboardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return /^[^\s\x00-\x1f\x7f]+$/u.test(trimmed);
}

/**
 * Normalize a single allowlist entry for PulseBoard.
 * Strips protocol/kind prefixes and lowercases the result for consistent matching.
 */
export function normalizePulseboardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  } else if (value.startsWith("@")) {
    value = value.slice(1);
  }
  return value.trim();
}

export function normalizePulseboardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? [])
    .map((entry) => normalizePulseboardAllowEntry(String(entry)))
    .filter(Boolean);
}

/**
 * Check whether a sender username matches a PulseBoard allowlist.
 * Supports wildcard "*" for open access.
 */
export function resolvePulseboardAllowlistMatch(params: {
  allowFrom: string[];
  senderId: string;
}): { allowed: boolean; source?: string } {
  const normalized = new Set(
    params.allowFrom.map((e) => e.trim().toLowerCase()).filter(Boolean),
  );
  if (normalized.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const candidate = params.senderId.trim().toLowerCase();
  if (candidate && normalized.has(candidate)) {
    return { allowed: true, source: candidate };
  }
  return { allowed: false };
}

