import { resolvePulseboardAccount } from "./accounts.js";
import type { CoreConfig, PulseboardProbe } from "./types.js";

function formatError(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  return typeof err === "string" ? err : JSON.stringify(err);
}

/**
 * Probe the PulseBoard API by sending a lightweight GET to the /ping endpoint.
 * Returns latency on success and an error string on failure.
 */
export async function probePulseboard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseboardProbe> {
  const account = resolvePulseboardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseboardProbe = {
    ok: false,
    apiUrl: account.apiUrl,
    botUserId: account.botUserId,
  };

  if (!account.configured) {
    return { ...base, error: "missing token" };
  }

  const started = Date.now();
  const controller = new AbortController();
  const timeoutMs = opts?.timeoutMs ?? 8000;
  const timer = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const response = await fetch(`${account.apiUrl}/ping`, {
      method: "GET",
      headers: {
        Authorization: `Bearer ${account.token}`,
        "User-Agent": "openclaw-pulseboard/1.0",
      },
      signal: controller.signal,
    });
    clearTimeout(timer);

    if (!response.ok) {
      return {
        ...base,
        error: `HTTP ${response.status} ${response.statusText}`,
      };
    }

    return {
      ...base,
      ok: true,
      latencyMs: Date.now() - started,
    };
  } catch (err) {
    clearTimeout(timer);
    return { ...base, error: formatError(err) };
  }
}

