import { resolvePulseboardAccount } from "./accounts.js";
import { isBoardTarget, normalizePulseboardMessagingTarget } from "./normalize.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseboardResult = {
  messageId: string;
  target: string;
};

function recordPulseboardOutboundActivity(accountId: string): void {
  try {
    getPulseboardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    // Swallow "runtime not initialized" errors that can occur during setup.
    if (
      !(error instanceof Error) ||
      error.message !== "PulseBoard runtime not initialized"
    ) {
      throw error;
    }
  }
}

function buildMessageId(): string {
  return `pb-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
}

/**
 * Send a text message to a PulseBoard board or direct-message target.
 *
 * Board targets are prefixed with "#" (e.g. "#general").
 * Direct targets are plain usernames (e.g. "alice").
 */
export async function sendMessagePulseboard(
  to: string,
  text: string,
  opts: {
    cfg?: CoreConfig;
    accountId?: string;
    replyToId?: string;
  } = {},
): Promise<SendPulseboardResult> {
  const runtime = getPulseboardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseboardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need token in channels.pulseboard).`,
    );
  }

  const target = normalizePulseboardMessagingTarget(to);
  if (!target) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const payload = text.trim();
  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const isBoard = isBoardTarget(target);
  // Board name without "#" prefix for the API path.
  const boardName = isBoard ? target.slice(1) : null;

  const apiPath = isBoard
    ? `${account.apiUrl}/boards/${encodeURIComponent(boardName!)}/posts`
    : `${account.apiUrl}/dms/${encodeURIComponent(target)}/messages`;

  const body: Record<string, unknown> = { text: payload };
  if (opts.replyToId) {
    body.replyToId = opts.replyToId;
  }

  const response = await fetch(apiPath, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${account.token}`,
      "Content-Type": "application/json",
      "User-Agent": "openclaw-pulseboard/1.0",
    },
    body: JSON.stringify(body),
  });

  if (!response.ok) {
    const errText = await response.text().catch(() => response.statusText);
    throw new Error(
      `PulseBoard API error sending to ${target}: HTTP ${response.status} — ${errText}`,
    );
  }

  const messageId = buildMessageId();
  recordPulseboardOutboundActivity(account.accountId);

  return { messageId, target };
}

