import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import type { ResolvedPulseboardAccount } from "./accounts.js";
import { isBoardTarget, normalizePulseboardAllowlist, resolvePulseboardAllowlistMatch } from "./normalize.js";
import {
  resolvePulseboardBoardAccessGate,
  resolvePulseboardBoardMatch,
  resolvePulseboardBoardSenderAllowed,
  resolvePulseboardRequireMention,
} from "./policy.js";
import type { RuntimeEnv } from "./runtime-api.js";
import type { CoreConfig, PulseboardInboundMessage } from "./types.js";

type HandlePulseboardInboundParams = {
  message: PulseboardInboundMessage;
  account: ResolvedPulseboardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  sendReply: (target: string, text: string) => void | Promise<void>;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
};

function wasMentioned(text: string, botUserId: string): boolean {
  if (!botUserId) {
    return false;
  }
  // PulseBoard mentions use the form @username in message text.
  return text.includes(`@${botUserId}`);
}

export async function handlePulseboardInbound(params: HandlePulseboardInboundParams): Promise<void> {
  const { message, account, config, runtime, sendReply, statusSink } = params;
  const log = resolveLoggerBackedRuntime(runtime, undefined).log;

  statusSink?.({ lastInboundAt: message.timestamp });

  // Ignore our own messages to avoid echo loops.
  if (
    account.botUserId &&
    message.senderUserId.toLowerCase() === account.botUserId.toLowerCase()
  ) {
    return;
  }

  if (message.isGroup) {
    const boardMatch = resolvePulseboardBoardMatch({
      boards: account.config.boards,
      target: message.target,
    });
    const gate = resolvePulseboardBoardAccessGate({
      groupPolicy: account.config.groupPolicy,
      boardMatch,
    });
    if (!gate.allowed) {
      log?.(`[pulseboard/${account.accountId}] board ${message.target} dropped: ${gate.reason}`);
      return;
    }

    const outerAllowFrom = normalizePulseboardAllowlist(account.config.groupAllowFrom);
    const innerAllowFrom = normalizePulseboardAllowlist(boardMatch.boardConfig?.allowFrom);
    const senderAllowed = resolvePulseboardBoardSenderAllowed({
      groupPolicy: account.config.groupPolicy,
      senderId: message.senderUserId,
      outerAllowFrom,
      innerAllowFrom,
    });
    if (!senderAllowed) {
      log?.(
        `[pulseboard/${account.accountId}] board sender ${message.senderUserId} not in allowlist`,
      );
      return;
    }

    const requireMention = resolvePulseboardRequireMention({
      boardConfig: boardMatch.boardConfig,
      wildcardConfig: boardMatch.wildcardConfig,
    });
    if (requireMention && !wasMentioned(message.text, account.botUserId)) {
      return;
    }
  } else {
    // Direct message — check DM allowlist.
    const allowFrom = normalizePulseboardAllowlist(account.config.allowFrom);
    if (allowFrom.length > 0) {
      const { allowed } = resolvePulseboardAllowlistMatch({
        allowFrom,
        senderId: message.senderUserId,
      });
      if (!allowed) {
        log?.(
          `[pulseboard/${account.accountId}] DM from ${message.senderUserId} not in allowlist`,
        );
        return;
      }
    }
  }

  // Dispatch the message through the OpenClaw reply pipeline.
  await runtime.dispatch?.({
    channel: "pulseboard",
    accountId: account.accountId,
    messageId: message.messageId,
    target: message.target,
    senderId: message.senderUserId,
    text: message.text,
    isGroup: message.isGroup,
    timestamp: message.timestamp,
    sendReply: async (text: string) => {
      await sendReply(message.target, text);
      statusSink?.({ lastOutboundAt: Date.now() });
    },
  });
}

