import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseboardAccount } from "./accounts.js";
import { isBoardTarget } from "./normalize.js";
import { handlePulseboardInbound } from "./inbound.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig, PulseboardInboundMessage } from "./types.js";

/** Minimum polling interval in ms to avoid hammering the API. */
const POLL_INTERVAL_MS = 3000;

export type PulseboardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseboardInboundMessage) => void | Promise<void>;
};

/**
 * Long-running PulseBoard monitor that polls the /events endpoint and
 * dispatches inbound messages to the OpenClaw reply pipeline.
 *
 * PulseBoard uses a cursor-based events feed; we track the last seen event
 * cursor and request only new events on each poll cycle.
 */
export async function monitorPulseboardProvider(
  opts: PulseboardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseboardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseboardAccount({ cfg, accountId: opts.accountId });
  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(opts.runtime, core.logging.getChildLogger());

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need token in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let stopped = false;
  let lastCursor: string | null = null;

  logger.info(
    `[${account.accountId}] starting PulseBoard monitor (${account.apiUrl})`,
  );

  const poll = async () => {
    const cursorParam = lastCursor ? `?cursor=${encodeURIComponent(lastCursor)}` : "";
    const url = `${account.apiUrl}/events${cursorParam}`;

    let response: Response;
    try {
      response = await fetch(url, {
        method: "GET",
        headers: {
          Authorization: `Bearer ${account.token}`,
          "User-Agent": "openclaw-pulseboard/1.0",
        },
        signal: opts.abortSignal,
      });
    } catch (err) {
      if (opts.abortSignal?.aborted) {
        return;
      }
      logger.error(
        `[${account.accountId}] PulseBoard poll error: ${err instanceof Error ? err.message : String(err)}`,
      );
      return;
    }

    if (!response.ok) {
      logger.error(
        `[${account.accountId}] PulseBoard events API returned HTTP ${response.status}`,
      );
      return;
    }

    let data: unknown;
    try {
      data = await response.json();
    } catch {
      logger.error(`[${account.accountId}] PulseBoard events response was not valid JSON`);
      return;
    }

    // Expected shape: { cursor: string; events: Array<{ id, type, boardId?, senderId, text, timestamp }> }
    if (
      !data ||
      typeof data !== "object" ||
      !("events" in data) ||
      !Array.isArray((data as { events: unknown }).events)
    ) {
      return;
    }

    const { events, cursor } = data as {
      events: Array<{
        id: string;
        type: string;
        boardId?: string;
        senderId: string;
        text: string;
        timestamp: number;
      }>;
      cursor?: string;
    };

    if (typeof cursor === "string" && cursor) {
      lastCursor = cursor;
    }

    for (const event of events) {
      if (opts.abortSignal?.aborted || stopped) {
        break;
      }
      if (event.type !== "message") {
        continue;
      }

      const isGroup = Boolean(event.boardId);
      // Board messages use "#boardId" as the conversation target;
      // DMs use the sender's user ID.
      const target = isGroup ? `#${event.boardId}` : event.senderId;

      const message: PulseboardInboundMessage = {
        messageId: event.id,
        target,
        senderUserId: event.senderId,
        text: event.text,
        timestamp: event.timestamp ?? Date.now(),
        isGroup,
      };

      core.channel.activity.record({
        channel: "pulseboard",
        accountId: account.accountId,
        direction: "inbound",
        at: message.timestamp,
      });

      if (opts.onMessage) {
        await opts.onMessage(message);
        continue;
      }

      await handlePulseboardInbound({
        message,
        account,
        config: cfg,
        runtime,
        sendReply: async (replyTarget: string, text: string) => {
          const isBoard = isBoardTarget(replyTarget);
          const boardName = isBoard ? replyTarget.slice(1) : null;
          const apiPath = isBoard
            ? `${account.apiUrl}/boards/${encodeURIComponent(boardName!)}/posts`
            : `${account.apiUrl}/dms/${encodeURIComponent(replyTarget)}/messages`;

          await fetch(apiPath, {
            method: "POST",
            headers: {
              Authorization: `Bearer ${account.token}`,
              "Content-Type": "application/json",
              "User-Agent": "openclaw-pulseboard/1.0",
            },
            body: JSON.stringify({ text }),
          });

          opts.statusSink?.({ lastOutboundAt: Date.now() });
          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "outbound",
          });
        },
        statusSink: opts.statusSink,
      });
    }
  };

  // Run the poll loop until aborted or stopped.
  const runLoop = async () => {
    while (!stopped && !opts.abortSignal?.aborted) {
      await poll();
      if (stopped || opts.abortSignal?.aborted) {
        break;
      }
      // Wait between polls unless aborted.
      await new Promise<void>((resolve) => {
        const timer = setTimeout(resolve, POLL_INTERVAL_MS);
        opts.abortSignal?.addEventListener("abort", () => {
          clearTimeout(timer);
          resolve();
        });
      });
    }
    logger.info(`[${account.accountId}] PulseBoard monitor stopped`);
  };

  // Start the loop asynchronously so the caller gets the stop handle immediately.
  void runLoop();

  return {
    stop: () => {
      stopped = true;
    },
  };
}

