      enabled: true,
      token: setupInput.token?.trim(),
      apiUrl: setupInput.apiUrl?.trim() || undefined,
      botUserId: setupInput.botUserId?.trim() || undefined,
    };
    return patchScopedAccountConfig({
      cfg: namedConfig,
      channelKey: channel,
      accountId,
      patch,
    }) as CoreConfig;
  },
};

